impl From<glam::Vec2> for Vector2 {
    fn from(v: glam::Vec2) -> Self {
        Self {
            data: [v.x, v.y],
        }
    }
}
impl From<Vector2> for glam::Vec2 {
    fn from(v: Vector2) -> Self {
        glam::Vec2::new(v.data[0], v.data[1])
    }
}

